const e={name:"Krasse",icon:"krasse",category:"kryddor",family:"Korsblommiga",familyLatin:"Brassicaceae",perennial:!1,difficulty:"Enkel",difficultyWhy:"Världens enklaste växt att odla. Gror på 2-3 dagar, klar att skörda efter en vecka. Behöver inte ens jord - ett fuktigt hushållspapper räcker. Perfekt för barn och otåliga odlare.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5,6,7,8]},days:"7-10",spacing:"Så tätt",spacingNote:"Mikrogrönt - strö jämnt",rowSpacing:"15 cm",depth:"Ytså",depthNote:"Strö på ytan - täck inte",ph:{min:6,max:6.8,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Flexibel. Växer bra i fönsterkarmen, på balkongen eller utomhus. Halvskugga fungerar fint - krassens korta livscykel gör att hon inte hinner bry sig om perfekta ljusförhållanden."},temperature:{min:5,max:30,ideal:"15-20°C",detail:"Gror redan vid 5°C men trivs bäst i rumstemperatur. Tål inte frost men det spelar sällan roll - de flesta odlar krasse inomhus året runt."},wind:{level:"Tålig",detail:"Skyddad odling inomhus är normen. Utomhus klarar hon lite vind, men plantorna är så späda att kraftig vind kan torka ut dem."}},watering:{need:"Hög",icon:"water",summary:"Krasse vill ha konstant fukt - fröna och de späda plantorna får ALDRIG torka ut. Vattna dagligen eller håll underlaget (papper/bomull) genomfuktigt.",phases:[{phase:"Groning (dag 1-3)",need:"Hög",tip:"Fröna måste ligga fuktigt hela tiden. Spraya med vattenspruta 1-2 gånger om dagen. De gror på bara 1-3 dagar!"},{phase:"Tillväxt (dag 3-7)",need:"Hög",tip:"Fortsätt hålla fuktigt. Plantorna är så tunna att de torkar ut på nolltid."},{phase:"Skörd (dag 7-10)",need:"Medel",tip:"Klipp med sax vid basen. Ingen återväxt - så en ny omgång istället!"}],mistakes:["Låter underlaget torka ut - fröna dör eller plantorna vissnar direkt","Övervattnar så det står vatten - kan ge mögel, särskilt inomhus"],tip:"Spraya med vattenspruta istället för att hälla - ger jämn fukt utan att skölja bort de små fröna."},soil:"Krasse behöver inte ens jord! Växer på fuktigt hushållspapper, bomull, hampmatta eller vatten. För utomhusodling fungerar vanlig trädgårdsjord utmärkt.",soilTips:["Hushållspapper på en tallrik - enklaste metoden, fungerar perfekt","Bomullstuss i en skål - klassikern för barn och skolor","Fuktig såjord i en låg kruka - ger lite kraftigare plantor","Äggskal fyllda med bomull - tradition till påsk!"],timeline:{1:[{phase:"Inomhussådd (året runt)",months:"Jan-dec",icon:"indoor"},{phase:"Utomhussådd",months:"Apr-sep",icon:"seedling"},{phase:"Skörd (7-10 dagar efter sådd)",months:"Jan-dec",icon:"harvest"}],4:[{phase:"Inomhussådd (året runt)",months:"Jan-dec",icon:"indoor"},{phase:"Utomhussådd",months:"Maj-sep",icon:"seedling"},{phase:"Skörd (7-10 dagar efter sådd)",months:"Jan-dec",icon:"harvest"}],6:[{phase:"Inomhussådd (året runt)",months:"Jan-dec",icon:"indoor"},{phase:"Utomhussådd",months:"Jun-aug",icon:"seedling"},{phase:"Skörd (7-10 dagar efter sådd)",months:"Jan-dec",icon:"harvest"}]},nutritionData:[{month:"Jan",N:2,P:1,K:1},{month:"Mar",N:2,P:1,K:1},{month:"Jun",N:2,P:1,K:1},{month:"Sep",N:2,P:1,K:1}],nutritionTips:[{timing:"Aldrig",tip:"Krasse behöver INGEN gödsling. Med en livscykel på 7-10 dagar hinner hon inte ens sakna näring. Fukt och ljus räcker."}],companions:{good:[{id:"sallat",name:"Sallat",icon:"vegetable",why:"Liknande krav på fukt och svalka. Krasse kan sås som snabb markbetäckare mellan sallatrader."},{id:"radisa",name:"Rädisa",icon:"vegetable",why:"Samma familj (korsblommiga) och liknande snabbväxande karaktär. Goda grannar i pallkragen."}],bad:[{id:"vitkal",name:"Kålväxter",icon:"vegetable",why:"Samma familj - kan dela sjukdomar vid upprepad odling på samma plats. Mest relevant vid utomhusodling."}]},rotation:{avoid:[{id:"radisa",name:"Rädisa"},{id:"vitkal",name:"Kålväxter"},{id:"broccoli",name:"Broccoli"}],avoidWhy:"Korsblommiga delar sjukdomar. Men krasse odlas nästan alltid inomhus på papper - då är växtföljd inte relevant.",goodBefore:[{name:"Allt"}],goodBeforeWhy:"Krasse tar ingenting från jorden (odlas ju oftast utan jord!).",goodAfter:[{name:"Allt"}],goodAfterWhy:"Irrelevant - krasse odlas nästan alltid i sin egen lilla värld på fönsterbrädan."},varieties:[{name:"Smörgåskrasse (standard)",zones:[1,2,3,4,5,6,7,8],note:"Klassikern med slätbladiga plantor. Snabb, pålitlig, pepprigt god. Finns hos alla svenska fröhandlare."},{name:"Cresso (krusbladig)",zones:[1,2,3,4,5,6,7,8],note:"Krusiga blad, extra vitaminrik. Snabbväxande och snygg på smörgåsen. Finns hos Impecta."},{name:"Broadleaved (storbladig)",zones:[1,2,3,4,5,6,7,8],note:"Större blad, lättare att skörda. Snabbväxande. Finns hos Impecta och Blomsterlandet."}],problems:[{name:"Mögel",symptom:"Vitt ludd på underlaget eller kring fröna, särskilt inomhus.",fix:"Bättre luftcirkulation! Täck inte helt lufttätt. Undvik att övervattna - fuktigt men inte dränkt."},{name:"Uttorkning",symptom:"Plantorna hänger och vissnar.",fix:"Krassens enda fiende. Håll underlaget konstant fuktigt - det tar bara en timme utan vatten för att förlora hela omgången."}],goodToKnow:[{icon:"tip",title:"Från frö till tallrik på 7 dagar",text:"Inget annat du kan odla kommer ens i närheten. Krasse gror på 1-3 dagar och är klar att äta efter en vecka. Omedelbar belöning för den otåliga odlaren.",severity:"tip"},{icon:"tip",title:"Behöver inte ens jord",text:"Fuktigt hushållspapper, bomull eller en våt svamp räcker. Strö på fröna, håll fuktigt, klipp efter en vecka. Enklare odling finns inte.",severity:"tip"},{icon:"tip",title:"Barnens första odling",text:'Det klassiska "första odlingsprojektet" för svenska barn. Omedelbar gratifikation, noll chans att misslyckas. Så i äggskal till påsk - en svensk tradition!',severity:"tip"},{icon:"tip",title:"Färskt året runt",text:"En av extremt få grödor du kan skörda färsk VARJE VECKA hela året, i vilken lägenhet som helst. Så en ny omgång var 5-7:e dag för obruten tillgång.",severity:"tip"},{icon:"warning",title:"Inte samma sak som indiankrasse",text:"Smörgåskrasse (Lepidium sativum, korsblommiga) och indiankrasse (Tropaeolum majus, indiankrasseväxter) är HELT olika växter som råkar dela namn och pepprig smak. Indiankrasse är en blommande klätterväxt, smörgåskrasse är mikrogrönt.",severity:"warning"}],sowing:{method:"direct",label:"Direktsådd (inomhus eller ute)",description:"Världens enklaste sådd. Strö fröna tätt på ett fuktigt underlag - hushållspapper, bomull, jord eller hampmatta. Håll fuktigt. Klipp efter 7-10 dagar. Klart.",steps:["Välj underlag: fuktigt hushållspapper på en tallrik, bomull i en skål, eller tunn jord i en kruka","Fukta underlaget ordentligt (blött men inte dränkt)","Strö fröna tätt över ytan - de ska nästan röra varandra","Spraya med vatten och ställ ljust (fönsterkarm perfekt)","Spraya dagligen - underlaget får ALDRIG torka ut","Groning på 1-3 dagar","Klipp med sax vid basen efter 7-10 dagar när plantorna är 5-10 cm"],tips:["Successionsådd var 5-7 dagar = obruten tillgång på färsk krasse","Så i äggskal med bomull till påsk - klassisk svensk tradition","Fröna är billiga - köp stort och så generöst","Ingen återväxt efter klippning - så en ny omgång istället"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Självpollinerande",biennial:!1,description:"Låt plantor växa förbi skördemogen ålder. De blommar snabbt med små vita blommor och sätter fröskidor. Skörda skidorna när de blivit ljusbruna.",steps:["Låt en omgång plantor växa vidare istället för att skörda","Plantorna blommar efter 4-6 veckor med små vita blommor","Fröskidor bildas och mognar (blir ljusbruna)","Klipp av innan skidorna öppnar sig helt","Torka i papperspåse och tröska ur fröna","Förvara torrt - hållbara 2-5 år"],isolation:"Krasse är till stor del självpollinerande. Håll bara en sort blommande åt gången för helt sortrena frön.",storageYears:"2-5 år",tip:"Men ärligt talat - krasse-frön kostar nästan ingenting. Spara frö mest för kul, inte av nödvändighet!"},storage:{shelfLife:"Bäst direkt (ingen förvaring!)",methods:[{method:"Levande på fönsterbrädan (bäst!)",icon:"indoor",duration:"Tills du klipper",description:"Låt plantorna stå och klipp efter behov. Det är den BÄSTA förvaringen - levande och färsk. Kan inte bli enklare.",best:!0},{method:"Färsk i kylskåp",icon:"water",duration:"2-3 dagar",description:"Klippt krasse i fuktig hushållspapper i kylskåp. Men den tappar krispighet snabbt - ät helst direkt.",best:!1}],tips:["Klipp bara det du behöver, låt resten stå - levande växter är bästa förvaringen","Kan varken frysas eller torkas - all smak och näring försvinner",'Successionsådd är det enda "förvaringstricket" som fungerar']},harvestCalc:{minPerSqm:.1,maxPerSqm:.3,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp med sax vid basen, 5-10 cm höga",description:"Klipp hela omgången på en gång med sax, nära basen. Varje frö ger bara en planta utan återväxt. Använd helst rå - smaken försvinner vid tillagning.",uses:[{use:"Smörgås",tip:"DEN klassiska användningen - smörgåskrasse heter det av en anledning. En skvätt krasse på en ost- eller äggsmörgås lyfter allt."},{use:"Sallad & garnering",tip:"Strö över färdiga rätter för pepprig fräschör. Vackert och gott på soppor, potatismos och ägghalvor."},{use:"Smoothies",tip:"Mixa med frukt och yoghurt. Krassens pepprighet balanseras fint av sötma."},{use:"Färskost & smör",tip:"Blanda finhackad krasse i färskost eller mjukt smör. Fantastiskt på nybakat bröd."}]}};export{e as krasse};
